const https = require('https');
const fs = require('fs');
const path = require('path');

const url = 'https://raw.githubusercontent.com/pensnarik/german-cities/master/germany.json';

const transformString = (str) => {
    return str
        .toLowerCase()
        .replace(/ä/g, 'ae')
        .replace(/ö/g, 'oe')
        .replace(/ü/g, 'ue')
        .replace(/ß/g, 'ss')
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-+|-+$/g, '');
};

https.get(url, (res) => {
    let data = '';

    res.on('data', (chunk) => {
        data += chunk;
    });

    res.on('end', () => {
        try {
            const records = JSON.parse(data);
            const uniqueCities = new Map();

            // Ensure we keep the top 6 cities first, as they were in the original array
            const initialCities = [
                { name: 'Köln', slug: 'koeln', region: 'Nordrhein-Westfalen', regionSlug: 'nordrhein-westfalen' },
                { name: 'Düsseldorf', slug: 'duesseldorf', region: 'Nordrhein-Westfalen', regionSlug: 'nordrhein-westfalen' },
                { name: 'Dortmund', slug: 'dortmund', region: 'Nordrhein-Westfalen', regionSlug: 'nordrhein-westfalen' },
                { name: 'Essen', slug: 'essen', region: 'Nordrhein-Westfalen', regionSlug: 'nordrhein-westfalen' },
                { name: 'Frankfurt am Main', slug: 'frankfurt', region: 'Hessen', regionSlug: 'hessen' },
                { name: 'München', slug: 'muenchen', region: 'Bayern', regionSlug: 'bayern' }
            ];

            initialCities.forEach(city => uniqueCities.set(city.name, city));

            records.forEach(record => {
                if (!record.name) return;

                const cityName = record.name;
                // The Pensnarik json uses 'state' instead of 'bundesland'
                let regionName = record.state || 'Deutschland';

                if (!uniqueCities.has(cityName)) {
                    uniqueCities.set(cityName, {
                        name: cityName,
                        slug: transformString(cityName),
                        region: regionName,
                        regionSlug: transformString(regionName)
                    });
                }
            });

            const allCitiesList = Array.from(uniqueCities.values());

            // Deduplicate by slug just in case
            const uniqueSlugs = new Set();
            const finalCities = [];

            allCitiesList.forEach(city => {
                if (!uniqueSlugs.has(city.slug)) {
                    uniqueSlugs.add(city.slug);
                    finalCities.push(city);
                }
            });

            let fileContent = `export const cities = [\n`;
            finalCities.forEach(city => {
                fileContent += `    { name: ${JSON.stringify(city.name)}, slug: '${city.slug}', region: ${JSON.stringify(city.region)}, regionSlug: '${city.regionSlug}' },\n`;
            });
            fileContent += `];\n`;

            const targetPath = path.join(__dirname, 'src', 'data', 'cities.ts');
            fs.writeFileSync(targetPath, fileContent, 'utf8');

            console.log(`Successfully wrote ${finalCities.length} unique cities and villages to src/data/cities.ts`);

        } catch (e) {
            console.error('Error parsing JSON or writing file:', e.message);
        }
    });
}).on('error', (e) => {
    console.error('Network Error:', e.message);
});

"use client";

import { useState, useMemo } from 'react';
import Link from 'next/link';
import { cities } from '@/data/cities';

export default function StateClient({ stateSlug, lang, dict }: { stateSlug: string, lang: string, dict: any }) {
    // Find cities belonging to this state
    const stateCities = useMemo(() => {
        return cities.filter(city => city.regionSlug === stateSlug)
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [stateSlug]);

    const stateName = stateCities.length > 0 ? stateCities[0].region : 'Bundesland';

    const [searchTerm, setSearchTerm] = useState('');

    const filteredCities = stateCities.filter(city =>
        city.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (stateCities.length === 0) {
        return (
            <div className="section-padding container text-center" style={{ paddingTop: '8rem' }}>
                <div className="section-padding container text-center" style={{ paddingTop: '8rem' }}>
                    <h1>{dict.seoPages.stateNotFound}</h1>
                    <Link href={`/${lang}/einsatzgebiet`} className="btn btn-primary" style={{ marginTop: '2rem' }}>{dict.seoPages.backToOverview}</Link>
                </div>
            </div>
        );
    }

    return (
        <div>
            <section className="section-padding" style={{ backgroundColor: 'var(--secondary)', paddingTop: '8rem', paddingBottom: '4rem' }}>
                <div className="container text-center">
                    <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'center', color: 'var(--muted)', fontSize: '0.9rem', marginBottom: '2rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                        <Link href={`/${lang}/einsatzgebiet`} style={{ textDecoration: 'none', color: 'inherit' }}>{dict.seoPages.locations}</Link>
                        <span>&gt;</span>
                        <span style={{ color: 'var(--primary)' }}>{stateName}</span>
                    </div>

                    <h1>{dict.seoPages.cityHeroTitle} {stateName}</h1>
                    <p style={{ maxWidth: '800px', margin: '0 auto 2rem', fontSize: '1.25rem' }}>
                        {dict.seoPages.stateDesc} {stateName}.
                    </p>

                    <div style={{ maxWidth: '500px', margin: '0 auto' }}>
                        <input
                            type="text"
                            placeholder={dict.seoPages.searchCityPlaceholder}
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            style={{
                                width: '100%',
                                padding: '1rem',
                                fontSize: '1.1rem',
                                border: '1px solid var(--border)',
                                borderRadius: 'var(--radius-sm)',
                                outline: 'none',
                                transition: 'border-color 0.2s ease',
                            }}
                            onFocus={(e) => { e.target.style.borderColor = 'var(--primary)'; }}
                            onBlur={(e) => { e.target.style.borderColor = 'var(--border)'; }}
                        />
                    </div>
                </div>
            </section>

            <section className="section-padding">
                <div className="container">
                    {filteredCities.length > 0 ? (
                        <div className="grid grid-cols-4" style={{ gap: '1.5rem' }}>
                            {filteredCities.map((city) => (
                                <Link
                                    key={city.slug}
                                    href={`/${lang}/einsatzgebiet/${stateSlug}/${city.slug}`}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'space-between',
                                        padding: '1.5rem',
                                        border: '1px solid var(--border)',
                                        borderRadius: 'var(--radius-sm)',
                                        textDecoration: 'none',
                                        color: 'inherit',
                                        transition: 'all 0.2s ease',
                                        backgroundColor: 'white'
                                    }}
                                    className="city-card"
                                >
                                    <span style={{ fontWeight: 500, fontSize: '1.1rem' }}>{city.name}</span>
                                </Link>
                            ))}
                        </div>
                    ) : (
                        <div className="text-center" style={{ padding: '3rem', backgroundColor: 'var(--secondary)', borderRadius: 'var(--radius-sm)' }}>
                            <p style={{ fontSize: '1.25rem', color: 'var(--secondary-foreground)' }}>
                                {dict.seoPages.noCityMatches} {stateName} {dict.seoPages.noCityFound} "{searchTerm}" {dict.seoPages.noCityMatches2}
                            </p>
                            <p style={{ marginTop: '1rem' }}>
                                {dict.seoPages.howeverWeDo} <Link href={`/${lang}/kontakt`} style={{ color: 'var(--primary)', textDecoration: 'underline' }}>{dict.seoPages.askDirectly}</Link>
                            </p>
                        </div>
                    )}
                </div>
            </section>

            <style dangerouslySetInnerHTML={{
                __html: `
        .city-card:hover {
          border-color: var(--primary) !important;
          transform: translateY(-5px);
          box-shadow: 0 10px 30px rgba(0,0,0,0.05);
        }
      `}} />
        </div>
    );
}

import { notFound } from 'next/navigation';
import Link from 'next/link';
import { cities } from '@/data/cities';
import { getCategories, getServiceBySlug } from '@/data/services';
import type { Metadata } from 'next';
import { getDictionary } from '@/get-dictionary';
import type { Locale } from '@/i18n-config';

type Props = {
    params: Promise<{ lang: string; state: string; city: string; category: string }>;
};

export async function generateMetadata({ params }: Props): Promise<Metadata> {
    const { city: citySlug, state: stateSlug, category: categorySlug } = await params;
    const city = cities.find(c => c.slug === citySlug && c.regionSlug === stateSlug);
    const category = getServiceBySlug(categorySlug);

    if (!city || !category || !category.isCategory) {
        return { title: 'Nicht gefunden | Octabau' };
    }

    return {
        title: `${category.title} in ${city.name} | Octabau`,
        description: `Octabau ist Ihr professioneller Partner für ${category.title} in ${city.name} und Umgebung. Entdecken Sie unsere Leistungen.`,
    };
}

export async function generateStaticParams() {
    const params: { lang: string; state: string; city: string; category: string }[] = [];
    const categories = getCategories();

    // Only pre-build the top 5 cities, the rest are generated on-demand.
    const topCities = cities.slice(0, 5);

    for (const city of topCities) {
        for (const cat of categories) {
            for (const lang of ['de', 'en', 'ar']) {
                params.push({ lang, state: city.regionSlug, city: city.slug, category: cat.slug });
            }
        }
    }
    return params;
}

export default async function CityCategoryPage({ params }: Props) {
    const { lang, city: citySlug, state: stateSlug, category: categorySlug } = await params;
    const dict = await getDictionary(lang as Locale);

    const cityData = cities.find(c => c.slug === citySlug && c.regionSlug === stateSlug);
    const categoryData = getServiceBySlug(categorySlug);

    if (!cityData || !categoryData || !categoryData.isCategory) {
        notFound();
    }

    // Get sub-services for this category
    const { getSubServices } = await import('@/data/services');
    const subServices = getSubServices(categoryData.slug);

    return (
        <div>
            {/* Hero Section */}
            <section className="section-padding" style={{ backgroundColor: 'var(--primary)', color: 'white', paddingTop: '8rem', paddingBottom: '4rem', position: 'relative' }}>
                <div style={{ position: 'absolute', inset: 0, zIndex: 0, opacity: 0.2 }}>
                    <img
                        src={categoryData.image || "/images/generic.png"}
                        alt={categoryData.title}
                        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                </div>
                <div className="container" style={{ position: 'relative', zIndex: 1 }}>
                    <div style={{ display: 'flex', gap: '0.5rem', color: 'rgba(255,255,255,0.7)', fontSize: '0.9rem', marginBottom: '2rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                        <Link href={`/${lang}/einsatzgebiet/${cityData.regionSlug}`} style={{ textDecoration: 'none', color: 'inherit' }}>{cityData.region}</Link>
                        <span>&gt;</span>
                        <Link href={`/${lang}/einsatzgebiet/${cityData.regionSlug}/${cityData.slug}`} style={{ textDecoration: 'none', color: 'inherit' }}>{cityData.name}</Link>
                        <span>&gt;</span>
                        <span style={{ color: 'white' }}>{categoryData.title}</span>
                    </div>

                    <h1 style={{ fontSize: '3rem', marginBottom: '1.5rem', maxWidth: '800px', lineHeight: 1.1 }}>
                        {categoryData.title} {dict.categoryPage.in} {cityData.name}
                    </h1>
                    <p style={{ fontSize: '1.25rem', color: 'rgba(255,255,255,0.8)', maxWidth: '700px' }}>
                        {dict.categoryPage.heroDesc1} {categoryData.title}{dict.categoryPage.heroDesc2} {cityData.name}.
                    </p>
                </div>
            </section>

            {/* General Description */}
            <section className="section-padding">
                <div className="container grid grid-cols-2" style={{ gap: '4rem', alignItems: 'center' }}>
                    <div>
                        <h2 style={{ fontSize: '2rem', marginBottom: '1.5rem' }}>{dict.categoryPage.regExpertise} {cityData.name}</h2>
                        <p style={{ fontSize: '1.1rem', marginBottom: '1.5rem', color: 'var(--secondary-foreground)' }}>
                            {categoryData.description}
                        </p>
                        <p style={{ color: 'var(--secondary-foreground)' }}>
                            {dict.categoryPage.trustDesc} {cityData.name}{dict.categoryPage.trustDesc2} {categoryData.title}{dict.categoryPage.trustDesc3}
                        </p>
                    </div>
                    <div style={{ backgroundColor: 'var(--secondary)', padding: '3rem', borderRadius: 'var(--radius-sm)' }}>
                        <h3 style={{ fontSize: '1.5rem', marginBottom: '1rem' }}>{dict.categoryPage.whyTitle} {cityData.name}?</h3>
                        <ul style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <li style={{ display: 'flex', gap: '1rem' }}>
                                <span style={{ color: 'var(--primary)', fontWeight: 'bold' }}>01</span>
                                <span>{dict.categoryPage.why1}</span>
                            </li>
                            <li style={{ display: 'flex', gap: '1rem' }}>
                                <span style={{ color: 'var(--primary)', fontWeight: 'bold' }}>02</span>
                                <span>{dict.categoryPage.why2} {cityData.region}</span>
                            </li>
                            <li style={{ display: 'flex', gap: '1rem' }}>
                                <span style={{ color: 'var(--primary)', fontWeight: 'bold' }}>03</span>
                                <span>{dict.categoryPage.why3}</span>
                            </li>
                        </ul>
                    </div>
                </div>
            </section>

            {/* Sub Services */}
            {subServices.length > 0 && (
                <section className="section-padding" style={{ backgroundColor: 'var(--secondary)' }}>
                    <div className="container">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '3rem' }}>
                            <div>
                                <h2 style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>{dict.categoryPage.specServices}</h2>
                                <p style={{ color: 'var(--secondary-foreground)', maxWidth: '600px', fontSize: '1.1rem' }}>
                                    {dict.categoryPage.chooseDetail} {cityData.name}.
                                </p>
                            </div>
                        </div>

                        <div className="grid grid-cols-3">
                            {subServices.map((sub) => (
                                <Link
                                    key={sub.id}
                                    href={`/${lang}/einsatzgebiet/${cityData.regionSlug}/${cityData.slug}/${categoryData.slug}/${sub.slug}`}
                                    style={{
                                        display: 'block',
                                        padding: '2rem',
                                        backgroundColor: 'white',
                                        border: '1px solid var(--border)',
                                        borderRadius: 'var(--radius-sm)',
                                        textDecoration: 'none',
                                        transition: 'transform 0.2s, box-shadow 0.2s',
                                        color: 'inherit'
                                    }}
                                    className="service-card"
                                >
                                    <h3 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>{sub.title}</h3>
                                    <p style={{ color: 'var(--muted)', fontSize: '0.95rem', marginBottom: '1.5rem' }}>
                                        {sub.description}
                                    </p>
                                    <span style={{ color: 'var(--primary)', fontWeight: 500, fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                                        {dict.categoryPage.detailsFor} {cityData.name} &rarr;
                                    </span>
                                </Link>
                            ))}
                        </div>
                    </div>
                </section>
            )}

            {/* CTA */}
            <section className="section-padding">
                <div className="container text-center">
                    <div style={{ backgroundColor: 'var(--primary)', color: 'white', padding: '5rem 2rem', borderRadius: 'var(--radius-sm)' }}>
                        <h2 style={{ fontSize: '2.5rem', color: 'white', marginBottom: '1rem' }}>{dict.categoryPage.planProj} {categoryData.title} {dict.categoryPage.in} {cityData.name}?</h2>
                        <p style={{ fontSize: '1.25rem', color: 'rgba(255,255,255,0.8)', maxWidth: '600px', margin: '0 auto 2.5rem' }}>
                            {dict.categoryPage.talkWithUs}
                        </p>
                        <Link href={`/${lang}/kontakt`} className="btn" style={{ backgroundColor: 'white', color: 'var(--primary)' }}>
                            {dict.categoryPage.requestNow} {cityData.name}
                        </Link>
                    </div>
                </div>
            </section>

            <style dangerouslySetInnerHTML={{
                __html: `
        .service-card:hover {
          transform: translateY(-5px);
          box-shadow: 0 10px 30px rgba(0,0,0,0.05);
          border-color: var(--primary) !important;
        }
      `}} />
        </div>
    );
}

import { notFound } from 'next/navigation';
import Link from 'next/link';
import { cities } from '@/data/cities';
import { getCategories } from '@/data/services';
import type { Metadata } from 'next';
import { getDictionary } from '@/get-dictionary';
import type { Locale } from '@/i18n-config';

type Props = {
    params: Promise<{ lang: string; state: string; city: string }>;
};

export async function generateMetadata({ params }: Props): Promise<Metadata> {
    const { city: citySlug, state: stateSlug } = await params;
    const city = cities.find(c => c.slug === citySlug && c.regionSlug === stateSlug);

    if (!city) {
        return { title: 'Standort nicht gefunden | Octabau' };
    }

    return {
        title: `Bauunternehmen in ${city.name} | Octabau`,
        description: `Ihr professionelles Bauunternehmen für Großprojekte und gewerblichen Bau in ${city.name} und der Region ${city.region}.`,
    };
}

export async function generateStaticParams() {
    // Only pre-build the first 5 cities to save build time.
    // The rest of the 2,000+ cities are generated on-demand.
    return cities.slice(0, 5).flatMap((city) => (
        ['de', 'en', 'ar'].map(lang => ({
            lang,
            state: city.regionSlug,
            city: city.slug,
        }))
    ));
}

export default async function CityPage({ params }: Props) {
